void modified()
{
    next modified();


    boolean freeze = ETGCanadaParametersHelper1::isExchangeRateFrozen();

    FormDataObject formDataObject = any2Object(this) as FormDataObject;
    FormRun formRun = formDataObject.datasource().formRun();
    FormDesign design = formRun.design();



    FormControl exchRateCtrl =design.controlName(identifierStr(Currency_M_editExchRate));
    FormControl repExchRateCtrl =design.controlName(identifierStr(ReportingfieldExchRate));
    FormControl edtExchRateCtrl =design.controlName(identifierStr(Currency_editExchRate));


    FormDataObject fdoExchRate  =formDataObject.datasource().object(fieldNum(LedgerJournalTrans,ExchRate));
    FormDataObject fdoReportingFieldExchRate=formDataObject.datasource().object(fieldNum(LedgerJournalTrans,ReportingCurrencyExchRate));

    if (!freeze)
    {
        exchRateCtrl.allowEdit(true);
        repExchRateCtrl.allowEdit(true);
        edtExchRateCtrl.allowEdit(true);
        fdoExchRate.allowEdit(true);
        fdoReportingFieldExchRate.allowEdit(true);


    }


    else
    {
        exchRateCtrl.allowEdit(false);
        repExchRateCtrl.allowEdit(false);
        edtExchRateCtrl.allowEdit(false);
        fdoExchRate.allowEdit(false);
        fdoReportingFieldExchRate.allowEdit(false);

    }

}
